+                        sdc0_activity <= wb_ext_io_in.dat(3);
+                    end if;
+                    if wb_sdcard2_cyc = '1' then
+                        sdc1_activity <= wb_ext_io_in.dat(3);
+                    end if;
+                end if;
             end if;
